#include<bits/stdc++.h>
using namespace std;
long long n,m,k,t,ans;
const long long mod=1e9+7;
struct mat
{
    long long r,c,a[33][33];
    mat()
    {
        memset(a,0,sizeof(a));
    }
    void init()
    {
        *this=mat();
        r=c=t;
        for(long long i=0;i<c;i++)
        {
            a[i][i]=1;
        }
    }
    mat operator*(const mat&x)const
    {
        mat ans;
        ans.r=r;
        ans.c=c;
        for(long long i=0;i<r;i++)
        {
            for(long long j=0;j<c;j++)
            {
                for(long long k=0;k<c;k++)
                {
                    ans.a[i][j]+=1ll*a[i][k]*x.a[k][j]%mod;
                    ans.a[i][j]%=mod;
                }
            }
        }
        return ans;
    }
    mat operator^(long long y)
    {
        mat ans,x=(*this);
        ans.init();
        while(y)
        {
            if(y%2==1)
            {
                ans=ans*x;
            }
            x=x*x;
            y/=2;
        }
        return ans;
    }
};
int main()
{
    scanf("%lld%lld%lld",&n,&m,&k);
    t=(1<<m);
    mat b;
    b.r=b.c=t;
    for(long long i=0;i<t;i++)
    {
        if(__builtin_popcount(i)>k)
        {
            continue;
        }
        long long j=i>>1;
        b.a[j][i]=1;
        j=(i>>1)|(1<<(m-1));
        if(__builtin_popcount(j)<=k)
        {
            b.a[j][i]=1;
        }
    }
    mat res=(b^n);
    long long ans=0;
    for(long long i=0;i<t;i++)
    {
        ans+=res.a[i][i];
        ans%=mod;
    }
    printf("%lld",ans);
    return 0;
}
